.disparity-header strong {
  color: #c0392b;
}

.disparity-metric {
  font-size: 0.85rem;
  color: #2c3e50;
  margin-bottom: 4px;
}

.disparity-threshold {
  font-size: 0.8rem;
  color: #7f8c8d;
  font-style: italic;
  margin-bottom: 8px;
  padding-bottom: 8px;
  border-bottom: 1px dashed #f5c6cb;
