.border-warning {
  border-top-color: #f39c12;
}

.border-neutral {
  border-top-color: #95a5a6;
}

.badge {
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 0.85rem;
  font-weight: bold;
}

.badge-critical {
  background: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

.badge-warning {
  background: #fff3cd;
  color: #856404;
  border: 1px solid #ffeeba;
}

.badge-neutral {
  background: #e2e3e5;
  color: #383d41;
  border: 1px solid #d6d8db;
}

