appsmith.onReady(() => {
  renderRiskSignals();
});
appsmith.onModelChange(() => {
  renderRiskSignals();
});
function renderRiskSignals() {
  const data = appsmith.model;
  const observedVariables = data.observed_variables || [];
  const disparityMetrics = data.outcome_disparity_metrics || [];

  // 1. Categorization Logic
  const protectedCategories = ["Gender", "Age", "Ethnicity", "MaritalStatus"];
  const biasCategories = ["Salary", "JobRole", "StockOptionLevel", "OverTime", "Department"];
  const proxyCategories = ["DistanceFromHome (KM)", "State", "Education", "EducationField"];
  const foundProtected = observedVariables.filter(v => protectedCategories.includes(v));
  const foundBias = observedVariables.filter(v => biasCategories.includes(v));
  const foundProxy = observedVariables.filter(v => proxyCategories.includes(v));

  // 2. Helper to render attribute lists
  function populateList(elementId, countId, items) {
    const listEl = document.getElementById(elementId);
    const countEl = document.getElementById(countId);
    countEl.textContent = items.length;
    listEl.innerHTML = "";
    if (items.length === 0) {
      listEl.innerHTML = `<li><span style="color:#7f8c8d; font-style:italic;">No signals detected in this category.</span></li>`;
    } else {
      items.forEach(item => {
        const li = document.createElement('li');
        li.textContent = item;
        listEl.appendChild(li);
      });
    }
  }

  // Populate the first three cards
  populateList('list-protected', 'count-protected', foundProtected);
  populateList('list-bias', 'count-bias', foundBias);
  populateList('list-proxy', 'count-proxy', foundProxy);

  // 3. Render Outcome Disparity Signals
  populateDisparitySignals(disparityMetrics);
}
function populateDisparitySignals(metrics) {
  const container = document.getElementById('disparity-content');
  const countEl = document.getElementById('count-disparity');
  const confidenceEl = document.getElementById('disparity-confidence');
  countEl.textContent = metrics.length;
  container.innerHTML = "";
  if (metrics.length === 0) {
    container.innerHTML = `<div class="placeholder-state"><em>Awaiting runtime evaluation harness integration.</em></div>`;
    document.getElementById('disparity-card').className = "signal-card border-neutral";
    countEl.className = "badge badge-neutral";
    return;
  }
  metrics.forEach(item => {
    confidenceEl.textContent = item.confidence;
    const div = document.createElement('div');
    div.className = "disparity-item";
    div.innerHTML = `
            <div class="disparity-header">
                <strong>Impacted Segment: ${item.segment}</strong>
            </div>
            <div class="disparity-metric">
                <strong>Observed Delta:</strong> ${item.disparity}
            </div>
            <div class="disparity-threshold">
                ${item.threshold}
            </div>
            <div class="disparity-mitigation">
                <strong>Suggested Mitigation:</strong><br>
                ${item.mitigation}
            </div>
        `;
    container.appendChild(div);
  });
}

